import * as core from "@actions/core";
import { loadConfig } from "./config";
import { runPipeline } from "./pipeline";
import { collectGitHub } from "./sources/github";
import { collectArxiv } from "./sources/arxiv";
import { collectBlogs } from "./sources/blogs";
import { collectWebPages } from "./sources/web_pages";
import { collectRegistries } from "./sources/registry";
import { filterCandidates } from "./filter/keywords";
import { filterByMetadata } from "./filter/metadata";
import { dedup } from "./filter/dedup";
import { classifyCandidates } from "./classifier/llm";
import { createIssues } from "./output/issues";
import {
  loadState,
  saveState,
  filterSeenCandidates,
  recordCandidates,
} from "./state";
import type { RadarConfig } from "./config";
import type { Candidate } from "./sources/types";

async function collect(config: RadarConfig): Promise<Candidate[]> {
  const candidates: Candidate[] = [];

  if (config.sources.github) {
    candidates.push(...(await collectGitHub(config)));
  }
  if (config.sources.arxiv) {
    candidates.push(...(await collectArxiv(config)));
  }
  if (config.sources.blogs) {
    candidates.push(...(await collectBlogs(config)));
  }
  if (config.sources.web_pages) {
    candidates.push(...(await collectWebPages(config)));
  }
  if (config.sources.registries) {
    candidates.push(...(await collectRegistries(config)));
  }

  return candidates;
}

async function run(): Promise<void> {
  try {
    const configPath = core.getInput("config_path");
    const dryRun = core.getInput("dry_run") === "true";

    core.info(`Loading config from ${configPath}`);
    const config = loadConfig(configPath);

    // Load state
    const state = loadState(config.state_file);

    let result;
    try {
      result = await runPipeline(
        config,
        {
          collect,
          filter: async (candidates, cfg) => {
            // First filter out already-seen candidates
            const unseen = filterSeenCandidates(candidates, state);
            // Then apply keyword filtering, metadata filtering, and dedup
            const keywordFiltered = filterCandidates(unseen, cfg);
            const metadataFiltered = filterByMetadata(keywordFiltered, cfg);
            const metadataResult = dedup(metadataFiltered, cfg);

            // Record candidates that were filtered out
            const filteredOut = unseen.filter(
              (c) => !metadataResult.includes(c)
            );
            recordCandidates(state, filteredOut, "filtered");

            return metadataResult;
          },
          classify: async (candidates, cfg) => {
            const classified = await classifyCandidates(candidates, cfg);

            // Record accepted (classified) and rejected (below threshold) candidates
            const classifiedUrls = new Set(classified.map((c) => c.url));
            const rejected = candidates.filter(
              (c) => !classifiedUrls.has(c.url)
            );
            recordCandidates(state, classified, "accepted");
            recordCandidates(state, rejected, "rejected");

            return classified;
          },
          output: createIssues,
        },
        dryRun
      );
    } finally {
      // Save state regardless of pipeline success/failure
      try {
        saveState(config.state_file, state);
      } catch (saveError) {
        core.warning(
          `Failed to save state: ${saveError instanceof Error ? saveError.message : String(saveError)}`
        );
      }
    }

    core.setOutput("candidates_found", result.candidatesFound);
    core.setOutput("candidates_filtered", result.candidatesFiltered);
    core.setOutput("issues_created", result.issuesCreated);
  } catch (error) {
    if (error instanceof Error) {
      core.setFailed(error.message);
    } else {
      core.setFailed("An unexpected error occurred");
    }
  }
}

run();

import { readFileSync } from "node:fs";
import { parse as parseYaml } from "yaml";
import { z } from "zod";

const GithubSourceSchema = z.object({
  topics: z.array(z.string()).min(1),
  languages: z.array(z.string()).optional(),
  min_stars: z.number().int().nonnegative().default(0),
  created_after: z
    .string()
    .regex(/^\d+d$/, 'Must be in format "Nd" (e.g. "30d")')
    .default("30d"),
  max_results: z.number().int().min(1).max(1000).default(100),
  sort: z.enum(["stars", "updated", "best-match"]).default("stars"),
  exclude_forks: z.boolean().default(false),
  exclude_archived: z.boolean().default(false),
});

const ArxivSourceSchema = z.object({
  categories: z.array(z.string()).min(1),
  keywords: z.array(z.string()).min(1),
  max_results: z.number().int().min(1).max(500).default(50),
  date_range: z
    .object({
      start: z
        .string()
        .regex(/^\d{8}(\d{6})?$/, "Must be YYYYMMDD or YYYYMMDDHHMMSS"),
      end: z
        .string()
        .regex(/^\d{8}(\d{6})?$/, "Must be YYYYMMDD or YYYYMMDDHHMMSS"),
    })
    .refine((r) => r.start <= r.end, {
      message: "date_range.start must be <= date_range.end",
    })
    .optional(),
});

const BlogsSourceSchema = z.object({
  feeds: z.array(z.string().url()).min(1),
  keywords: z.array(z.string()).optional(),
});

const WebPagesSourceSchema = z.object({
  urls: z.array(z.string().url()).min(1),
  keywords: z.array(z.string()).optional(),
  extraction_prompt: z.string().min(1).optional(),
  model: z.string().min(1).default("claude-haiku-4-5-20251001"),
  request_timeout: z.number().int().min(1000).max(120000).default(30000),
  user_agent: z.string().optional(),
});

const RegistryEntrySchema = z.object({
  type: z.enum(["npm", "pypi", "crates"]),
  keywords: z.array(z.string()).min(1),
  min_downloads: z.number().int().nonnegative().default(0),
  max_results: z.number().int().min(1).max(250).default(50),
});

const RegistrySourceSchema = z.array(RegistryEntrySchema).min(1);

const SourcesSchema = z.object({
  github: GithubSourceSchema.optional(),
  arxiv: ArxivSourceSchema.optional(),
  blogs: BlogsSourceSchema.optional(),
  web_pages: WebPagesSourceSchema.optional(),
  registries: RegistrySourceSchema.optional(),
});

const FilterSchema = z
  .object({
    include: z.array(z.string()).optional(),
    require_all: z.array(z.string()).optional(),
    exclude: z.array(z.string()).optional(),
    exclude_forks: z.boolean().default(false),
    exclude_archived: z.boolean().default(false),
    require_license: z.boolean().default(false),
    max_age_days: z.number().int().positive().optional(),
  })
  .default({});

const ClassificationSchema = z.object({
  model: z.string().default("claude-sonnet-4-6"),
  threshold: z.number().min(0).max(100).default(70),
  max_classifications_per_run: z.number().int().positive().optional(),
  max_issues_per_run: z.number().int().positive().optional(), // deprecated alias
  max_budget_usd: z.number().positive().optional(),
  system_prompt: z.string().optional(),
  context: z.string().optional(),
  max_description_length: z.number().int().positive().max(10000).default(500),
  categories: z.array(z.string()).optional(),
}).transform((val) => ({
  ...val,
  max_classifications_per_run: val.max_classifications_per_run ?? val.max_issues_per_run ?? 5,
}));

const IssueTemplateSchema = z.object({
  labels: z.array(z.string()).default(["radar", "needs-review"]),
  title_prefix: z.string().default("[Radar]"),
  include_fields: z.array(z.enum(["url", "source", "relevanceScore", "suggestedCategory", "tags", "stars", "language", "authors"])).optional(),
  suggested_entry_format: z.string().optional(),
});

export const RadarConfigSchema = z.object({
  description: z.string().min(1),
  list_file: z.string().default("README.md"),
  state_file: z.string().default(".radar-state.json"),
  sources: SourcesSchema.refine(
    (s) => s.github || s.arxiv || s.blogs || s.web_pages || s.registries,
    "At least one source must be configured"
  ),
  filter: FilterSchema,
  classification: ClassificationSchema.default({}),
  issue_template: IssueTemplateSchema.default({}),
});

export type RadarConfig = z.infer<typeof RadarConfigSchema>;

export function parseConfig(yamlContent: string): RadarConfig {
  const raw = parseYaml(yamlContent);
  return RadarConfigSchema.parse(raw);
}

export function loadConfig(filePath: string): RadarConfig {
  const content = readFileSync(filePath, "utf-8");
  return parseConfig(content);
}

