      ok: true,
      text: () => Promise.resolve("<html><body>Content</body></html>"),
    });

    const mockClient = {
      messages: {
        create: vi
          .fn()
          .mockRejectedValue(new Error("API error")),
      },
    } as any;

    const candidates = await collectWebPages(
      baseConfig,
      mockFetch as any,
      mockClient
    );
