export interface LLMRequest {
  model: string;
  maxTokens: number;
  system: string;
  messages: { role: "user" | "assistant"; content: string }[];
}

export interface LLMResponse {
  text: string;
  usage: { inputTokens: number; outputTokens: number };
}

export interface LLMProvider {
  chat(request: LLMRequest): Promise<LLMResponse>;
}

import Anthropic from "@anthropic-ai/sdk";
import type { LLMProvider, LLMRequest, LLMResponse } from "../types";

export class AnthropicProvider implements LLMProvider {
  private client: Anthropic;

  constructor(apiKey: string) {
    this.client = new Anthropic({ apiKey });
  }

  async chat(request: LLMRequest): Promise<LLMResponse> {
    const message = await this.client.messages.create({
      model: request.model,
      max_tokens: request.maxTokens,
      system: request.system,
      messages: request.messages,
    });

    return {
      text:
        message.content[0].type === "text" ? message.content[0].text : "",
      usage: {
        inputTokens: message.usage.input_tokens,
        outputTokens: message.usage.output_tokens,
      },
    };
  }
}

import OpenAI from "openai";
import type { LLMProvider, LLMRequest, LLMResponse } from "../types";

export class OpenAIProvider implements LLMProvider {
  private client: OpenAI;

  constructor(apiKey: string) {
    this.client = new OpenAI({ apiKey });
  }

  async chat(request: LLMRequest): Promise<LLMResponse> {
    const response = await this.client.chat.completions.create({
      model: request.model,
      max_tokens: request.maxTokens,
      messages: [
        { role: "system", content: request.system },
        ...request.messages,
      ],
    });

    return {
      text: response.choices[0]?.message?.content ?? "",
      usage: {
        inputTokens: response.usage?.prompt_tokens ?? 0,
        outputTokens: response.usage?.completion_tokens ?? 0,
      },
    };
  }
}

import { GoogleGenerativeAI } from "@google/generative-ai";
import type { LLMProvider, LLMRequest, LLMResponse } from "../types";

export class GoogleProvider implements LLMProvider {
  private client: GoogleGenerativeAI;

  constructor(apiKey: string) {
    this.client = new GoogleGenerativeAI(apiKey);
  }

  async chat(request: LLMRequest): Promise<LLMResponse> {
    const model = this.client.getGenerativeModel({
      model: request.model,
      systemInstruction: request.system,
    });

    const contents = request.messages.map((msg) => ({
      role: msg.role === "assistant" ? "model" : "user",
      parts: [{ text: msg.content }],
    }));

    const result = await model.generateContent({
      contents,
      generationConfig: { maxOutputTokens: request.maxTokens },
    });

    return {
      text: result.response.text(),
      usage: {
        inputTokens: result.response.usageMetadata?.promptTokenCount ?? 0,
        outputTokens:
          result.response.usageMetadata?.candidatesTokenCount ?? 0,
      },
    };
  }
}

export type { LLMProvider, LLMRequest, LLMResponse } from "./types";
import type { LLMProvider } from "./types";

export function createProvider(provider: string, apiKey: string): LLMProvider {
  switch (provider) {
    case "anthropic": {
      const { AnthropicProvider } = require("./providers/anthropic");
      return new AnthropicProvider(apiKey);
    }
    case "openai": {
      const { OpenAIProvider } = require("./providers/openai");
      return new OpenAIProvider(apiKey);
    }
    case "google": {
      const { GoogleProvider } = require("./providers/google");
      return new GoogleProvider(apiKey);
    }
    default:
      throw new Error(
        `Unknown LLM provider: "${provider}". Supported providers: anthropic, openai, google`
      );
  }
}

