144→function extractFirstJson(text: string): string {
145→  const start = text.indexOf("{");
146→  if (start === -1) throw new Error("No JSON found in LLM response");
147→  let depth = 0;
148→  for (let i = start; i < text.length; i++) {
149→    if (text[i] === "{") depth++;
150→    if (text[i] === "}") depth--;
151→    if (depth === 0) return text.slice(start, i + 1);
152→  }
153→  throw new Error("No valid JSON found in LLM response");
154→}
