178→export const MODEL_PRICING: Record<string, { inputPer1M: number; outputPer1M: number }> = {
179→  "claude-sonnet-4-6": { inputPer1M: 3.0, outputPer1M: 15.0 },
180→  "claude-haiku-4-5-20251001": { inputPer1M: 0.8, outputPer1M: 4.0 },
181→  "claude-opus-4-6": { inputPer1M: 15.0, outputPer1M: 75.0 },
182→};
183→
184→export function estimateCost(
185→  inputTokens: number,
186→  outputTokens: number,
187→  model: string
188→): number {
189→  const pricing = MODEL_PRICING[model];
190→  if (!pricing) {
191→    core.warning(`No pricing found for model "${model}"; falling back to claude-sonnet-4-6 pricing. Cost estimates may be inaccurate.`);
192→  }
193→  const effectivePricing = pricing ?? MODEL_PRICING["claude-sonnet-4-6"];
194→  return (inputTokens * effectivePricing.inputPer1M + outputTokens * effectivePricing.outputPer1M) / 1_000_000;
195→}
