197→// Caps the number of LLM API calls per run. Candidates beyond this
198→// limit are not classified. This controls API cost, not the final
199→// number of issues created (which may be lower after threshold filtering).
200→export async function classifyCandidates(
201→  candidates: Candidate[],
202→  config: RadarConfig,
203→  client?: Anthropic
204→): Promise<ClassifiedCandidate[]> {
205→  if (candidates.length === 0) return [];
206→
207→  const anthropic =
208→    client ?? new Anthropic({ apiKey: core.getInput("anthropic_api_key") });
209→
210→  const maxClassifications = config.classification.max_classifications_per_run;
211→  const maxBudget = config.classification.max_budget_usd;
212→  const toClassify = candidates.slice(0, maxClassifications);
213→  const classified: ClassifiedCandidate[] = [];
214→  const systemPrompt = config.classification.system_prompt ?? SYSTEM_PROMPT;
215→  const categoryTree = loadCategoryTree(config);
216→
217→  let totalInputTokens = 0;
218→  let totalOutputTokens = 0;
219→  let totalCost = 0;
220→
221→  for (const candidate of toClassify) {
222→    // Budget check before each call
223→    if (maxBudget !== undefined && totalCost >= maxBudget) {
224→      core.warning(`Budget limit reached ($${totalCost.toFixed(4)} >= $${maxBudget}). Skipping remaining ${toClassify.length - classified.length} candidates.`);
225→      break;
226→    }
227→
228→    try {
229→      const message = await withRetry(() =>
230→        anthropic.messages.create({
231→          model: config.classification.model,
232→          max_tokens: 512,
233→          system: systemPrompt,
234→          messages: [
235→            {
236→              role: "user",
237→              content: buildUserPrompt(candidate, config, categoryTree),
238→            },
239→          ],
240→        })
241→      );
242→
243→      // Track token usage
244→      const inputTokens = message.usage?.input_tokens ?? 0;
245→      const outputTokens = message.usage?.output_tokens ?? 0;
246→      const cost = estimateCost(inputTokens, outputTokens, config.classification.model);
247→
248→      totalInputTokens += inputTokens;
249→      totalOutputTokens += outputTokens;
250→      totalCost += cost;
251→
252→      core.info(`Classification "${candidate.title}": ${inputTokens} in / ${outputTokens} out tokens ($${cost.toFixed(4)})`);
253→
254→
255→      const text =
256→        message.content[0].type === "text" ? message.content[0].text : "";
257→      const result = parseClassifyResponse(text);
258→
259→      if (result.relevanceScore >= config.classification.threshold) {
260→        classified.push({ ...candidate, ...result });
261→      } else {
262→        core.info(
263→          `Skipping "${candidate.title}" (score ${result.relevanceScore} < threshold ${config.classification.threshold})`
264→        );
265→      }
266→    } catch (error) {
267→      core.warning(
268→        `Classification failed for "${candidate.title}": ${error instanceof Error ? error.message : String(error)}`
269→      );
270→    }
271→  }
272→
273→  // Log summary
274→  core.info(`Classification summary: ${totalInputTokens} input tokens, ${totalOutputTokens} output tokens, estimated cost: $${totalCost.toFixed(4)}`);
275→
276→  return classified;
277→}
