 78→export async function collectWebPages(
 79→  config: RadarConfig,
 80→  fetchFn?: typeof fetch,
 81→  client?: Anthropic
 82→): Promise<Candidate[]> {
 83→  if (!config.sources.web_pages) return [];
 84→
 85→  const webPages = config.sources.web_pages;
 86→  const fetcher = fetchFn ?? fetch;
 87→  const timeout = webPages.request_timeout;
 88→  const userAgent = webPages.user_agent;
 89→  const anthropic =
 90→    client ?? new Anthropic({ apiKey: core.getInput("anthropic_api_key") });
 91→
 92→  const results = await Promise.allSettled(
 93→    webPages.urls.map(async (pageUrl) => {
 94→      core.info(`Fetching web page: ${pageUrl}`);
 95→
 96→      const fetchOptions: RequestInit = {
 97→        signal: AbortSignal.timeout(timeout),
 98→      };
 99→      if (userAgent) {
100→        fetchOptions.headers = { "User-Agent": userAgent };
101→      }
102→      const response = await withRetry(async () => {
103→        const res = await fetcher(pageUrl, fetchOptions);
104→        if (!res.ok) {
105→          throw Object.assign(new Error(`HTTP ${res.status} for ${pageUrl}`), {
106→            status: res.status,
107→          });
108→        }
109→        return res;
110→      });
111→      const html = await response.text();
112→      const cleaned = cleanHtml(html);
113→
114→      core.info(`Extracting links from ${pageUrl} (${cleaned.length} chars)`);
115→
116→      const message = await withRetry(() =>
117→        anthropic.messages.create({
118→          model: webPages.model,
119→          max_tokens: 4096,
120→          system: webPages.extraction_prompt || SYSTEM_PROMPT,
121→          messages: [
122→            {
123→              role: "user",
124→              content: `Extract all article/blog post links from this web page content:\n\n${cleaned}`,
125→            },
126→          ],
127→        })
128→      );
129→
130→      const text =
131→        message.content[0].type === "text" ? message.content[0].text : "[]";
132→      const links = extractFirstJsonArray(text);
133→
134→      // Resolve relative URLs
135→      const resolved = links.map((link) => ({
136→        ...link,
137→        url: resolveUrl(pageUrl, link.url),
138→      }));
139→
140→      return { pageUrl, links: resolved };
141→    })
142→  );
143→
144→  const candidates: Candidate[] = [];
145→
146→  for (const result of results) {
147→    if (result.status === "rejected") {
148→      core.warning(`Failed to process web page: ${result.reason}`);
149→      continue;
150→    }
151→
152→    const { pageUrl, links } = result.value;
153→
154→    for (const link of links) {
155→      if (!link.url || !link.title) continue;
156→
157→      const text = `${link.title} ${link.url}`;
158→
159→      // Optional keyword filtering
160→      if (webPages.keywords && webPages.keywords.length > 0) {
161→        if (!matchesKeywords(text, webPages.keywords)) continue;
162→      }
163→
164→      candidates.push({
165→        url: link.url,
166→        title: link.title,
167→        description: link.title.slice(0, MAX_DESCRIPTION_LENGTH),
168→        source: "web_page",
169→        metadata: {
170→          pageName: new URL(pageUrl).hostname,
171→        },
172→      });
173→    }
174→  }
175→
176→  return candidates;
177→}
