 23→async function collect(config: RadarConfig): Promise<Candidate[]> {
 24→  const candidates: Candidate[] = [];
 25→
 26→  if (config.sources.github) {
 27→    candidates.push(...(await collectGitHub(config)));
 28→  }
 29→  if (config.sources.arxiv) {
 30→    candidates.push(...(await collectArxiv(config)));
 31→  }
 32→  if (config.sources.blogs) {
 33→    candidates.push(...(await collectBlogs(config)));
 34→  }
 35→  if (config.sources.web_pages) {
 36→    candidates.push(...(await collectWebPages(config)));
 37→  }
 38→  if (config.sources.registries) {
 39→    candidates.push(...(await collectRegistries(config)));
 40→  }
 41→
 42→  return candidates;
 43→}
