 45→async function run(): Promise<void> {
 46→  try {
 47→    const configPath = core.getInput("config_path");
 48→    const dryRun = core.getInput("dry_run") === "true";
 49→
 50→    core.info(`Loading config from ${configPath}`);
 51→    const config = loadConfig(configPath);
 52→
 53→    // Load state
 54→    const state = loadState(config.state_file);
 55→
 56→    let result;
 57→    try {
 58→      result = await runPipeline(
 59→        config,
 60→        {
 61→          collect,
 62→          filter: async (candidates, cfg) => {
 63→            // First filter out already-seen candidates
 64→            const unseen = filterSeenCandidates(candidates, state);
 65→            // Then apply keyword filtering, metadata filtering, and dedup
 66→            const keywordFiltered = filterCandidates(unseen, cfg);
 67→            const metadataFiltered = filterByMetadata(keywordFiltered, cfg);
 68→            const metadataResult = dedup(metadataFiltered, cfg);
 69→
 70→            // Record candidates that were filtered out
 71→            const filteredOut = unseen.filter(
 72→              (c) => !metadataResult.includes(c)
 73→            );
 74→            recordCandidates(state, filteredOut, "filtered");
 75→
 76→            return metadataResult;
 77→          },
 78→          classify: async (candidates, cfg) => {
 79→            const classified = await classifyCandidates(candidates, cfg);
 80→
 81→            // Record accepted (classified) and rejected (below threshold) candidates
 82→            const classifiedUrls = new Set(classified.map((c) => c.url));
 83→            const rejected = candidates.filter(
 84→              (c) => !classifiedUrls.has(c.url)
 85→            );
 86→            recordCandidates(state, classified, "accepted");
 87→            recordCandidates(state, rejected, "rejected");
 88→
 89→            return classified;
 90→          },
 91→          output: createIssues,
 92→        },
 93→        dryRun
 94→      );
 95→    } finally {
 96→      // Save state regardless of pipeline success/failure
 97→      try {
 98→        saveState(config.state_file, state);
 99→      } catch (saveError) {
100→        core.warning(
101→          `Failed to save state: ${saveError instanceof Error ? saveError.message : String(saveError)}`
102→        );
103→      }
104→    }
105→
106→    core.setOutput("candidates_found", result.candidatesFound);
107→    core.setOutput("candidates_filtered", result.candidatesFiltered);
