 28→function sanitize(text: string, maxLength: number): string {
 29→  return text.slice(0, maxLength).replace(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g, "");
 30→}
 31→
 32→function buildUserPrompt(
 33→  candidate: Candidate,
 34→  config: RadarConfig,
 35→  categoryTree?: string
 36→): string {
 37→  const maxDescLen = config.classification.max_description_length;
 38→  const parts = [
 39→    `## List Description`,
 40→    config.description,
 41→  ];
 42→
 43→  if (config.classification.context) {
 44→    parts.push(``, `## Additional Context`, config.classification.context);
 45→  }
 46→
 47→  parts.push(
 48→    ``,
 49→    `## Candidate`,
 50→    `<candidate_title>${sanitize(candidate.title, 200)}</candidate_title>`,
 51→    `<candidate_url>${sanitize(candidate.url, 500)}</candidate_url>`,
 52→    `<candidate_source>${candidate.source}</candidate_source>`,
 53→    `<candidate_description>${sanitize(candidate.description, maxDescLen)}</candidate_description>`
 54→  );
 55→
 56→  if (candidate.metadata.stars !== undefined) {
 57→    parts.push(`<candidate_stars>${candidate.metadata.stars}</candidate_stars>`);
 58→  }
 59→  if (candidate.metadata.language) {
 60→    parts.push(
 61→      `<candidate_language>${sanitize(candidate.metadata.language, 50)}</candidate_language>`
 62→    );
 63→  }
 64→  if (candidate.metadata.authors?.length) {
 65→    parts.push(
 66→      `<candidate_authors>${sanitize(candidate.metadata.authors.join(", "), 200)}</candidate_authors>`
 67→    );
 68→  }
 69→  if (candidate.metadata.topics?.length) {
 70→    parts.push(
 71→      `<candidate_topics>${sanitize(candidate.metadata.topics.join(", "), 200)}</candidate_topics>`
 72→    );
 73→  }
 74→  if (candidate.metadata.license) {
 75→    parts.push(
 76→      `<candidate_license>${sanitize(candidate.metadata.license, 50)}</candidate_license>`
 77→    );
 78→  }
 79→  if (candidate.metadata.archived !== undefined) {
 80→    parts.push(
 81→      `<candidate_archived>${candidate.metadata.archived}</candidate_archived>`
 82→    );
 83→  }
 84→  if (candidate.metadata.fork !== undefined) {
 85→    parts.push(
 86→      `<candidate_fork>${candidate.metadata.fork}</candidate_fork>`
 87→    );
 88→  }
 89→  if (candidate.metadata.owner) {
 90→    parts.push(
 91→      `<candidate_owner>${sanitize(candidate.metadata.owner, 100)}</candidate_owner>`
 92→    );
 93→  }
 94→  if (candidate.metadata.homepage) {
 95→    parts.push(
 96→      `<candidate_homepage>${sanitize(candidate.metadata.homepage, 500)}</candidate_homepage>`
 97→    );
 98→  }
 99→  if (candidate.metadata.lastPushedAt) {
100→    parts.push(
101→      `<candidate_last_pushed>${sanitize(candidate.metadata.lastPushedAt, 50)}</candidate_last_pushed>`
102→    );
103→  }
104→
105→  if (categoryTree) {
106→    parts.push(
107→      ``,
108→      `## Available Categories`,
109→      categoryTree,
110→      ``,
111→      `Pick the most appropriate category from the list above.`
112→    );
113→  }
114→
115→  parts.push(``, `Rate relevance from 0-100 and suggest a category and tags.`);
116→  return parts.join("\n");
117→}
118→
119→function loadCategoryTree(config: RadarConfig): string | undefined {
120→  // Explicit categories take priority
121→  if (config.classification.categories?.length) {
122→    return config.classification.categories.map((c) => `- ${c}`).join("\n");
123→  }
124→
125→  // Auto-extract from list file
126→  try {
127→    const content = readFileSync(config.list_file, "utf-8");
128→    const nodes = extractCategories(content);
129→    if (nodes.length === 0) return undefined;
130→    return formatCategoryTree(nodes);
131→  } catch {
132→    // File doesn't exist or can't be read — skip gracefully
133→    return undefined;
134→  }
135→}
136→
137→interface ClassifyResult {
138→  relevanceScore: number;
139→  suggestedCategory: string;
140→  suggestedTags: string[];
141→  reasoning: string;
142→}
143→
144→function extractFirstJson(text: string): string {
145→  const start = text.indexOf("{");
146→  if (start === -1) throw new Error("No JSON found in LLM response");
147→  let depth = 0;
148→  for (let i = start; i < text.length; i++) {
149→    if (text[i] === "{") depth++;
150→    if (text[i] === "}") depth--;
151→    if (depth === 0) return text.slice(start, i + 1);
152→  }
153→  throw new Error("No valid JSON found in LLM response");
154→}
155→
156→function parseClassifyResponse(text: string): ClassifyResult {
157→  const jsonStr = extractFirstJson(text);
158→  const parsed = JSON.parse(jsonStr);
159→
160→  if (
161→    typeof parsed.relevanceScore !== "number" ||
162→    parsed.relevanceScore < 0 ||
163→    parsed.relevanceScore > 100
164→  ) {
165→    throw new Error("Invalid relevanceScore in LLM response");
166→  }
167→
168→  return {
169→    relevanceScore: Math.round(parsed.relevanceScore),
170→    suggestedCategory: String(parsed.suggestedCategory ?? "Uncategorized"),
171→    suggestedTags: Array.isArray(parsed.suggestedTags)
172→      ? parsed.suggestedTags.map(String)
173→      : [],
174→    reasoning: String(parsed.reasoning ?? ""),
175→  };
176→}
