178→export const MODEL_PRICING: Record<string, { inputPer1M: number; outputPer1M: number }> = {
179→  // Anthropic
180→  "claude-sonnet-4-6": { inputPer1M: 3.0, outputPer1M: 15.0 },
181→  "claude-haiku-4-5-20251001": { inputPer1M: 0.8, outputPer1M: 4.0 },
182→  "claude-opus-4-6": { inputPer1M: 15.0, outputPer1M: 75.0 },
183→  // OpenAI
184→  "gpt-4o": { inputPer1M: 2.5, outputPer1M: 10.0 },
185→  "gpt-4o-mini": { inputPer1M: 0.15, outputPer1M: 0.6 },
186→  "gpt-4.1": { inputPer1M: 2.0, outputPer1M: 8.0 },
187→  "gpt-4.1-mini": { inputPer1M: 0.4, outputPer1M: 1.6 },
188→  "gpt-4.1-nano": { inputPer1M: 0.1, outputPer1M: 0.4 },
189→  // Google
190→  "gemini-2.0-flash": { inputPer1M: 0.1, outputPer1M: 0.4 },
191→  "gemini-2.5-flash-preview-05-20": { inputPer1M: 0.15, outputPer1M: 0.6 },
192→  "gemini-2.5-pro-preview-05-06": { inputPer1M: 1.25, outputPer1M: 10.0 },
193→};
194→
195→export function estimateCost(
196→  inputTokens: number,
197→  outputTokens: number,
198→  model: string
199→): number {
200→  const pricing = MODEL_PRICING[model];
201→  if (!pricing) {
202→    core.warning(`No pricing found for model "${model}"; falling back to claude-sonnet-4-6 pricing. Cost estimates may be inaccurate.`);
203→  }
204→  const effectivePricing = pricing ?? MODEL_PRICING["claude-sonnet-4-6"];
205→  return (inputTokens * effectivePricing.inputPer1M + outputTokens * effectivePricing.outputPer1M) / 1_000_000;
206→}
207→
208→// Caps the number of LLM API calls per run. Candidates beyond this
209→// limit are not classified. This controls API cost, not the final
210→// number of issues created (which may be lower after threshold filtering).
211→export async function classifyCandidates(
212→  candidates: Candidate[],
213→  config: RadarConfig,
214→  client?: LLMProvider
215→): Promise<ClassifiedCandidate[]> {
216→  if (candidates.length === 0) return [];
217→
218→  if (!client) throw new Error("LLM client is required for classification");
219→
220→  const maxClassifications = config.classification.max_classifications_per_run;
221→  const maxBudget = config.classification.max_budget_usd;
222→  const toClassify = candidates.slice(0, maxClassifications);
223→  const classified: ClassifiedCandidate[] = [];
224→  const systemPrompt = config.classification.system_prompt ?? SYSTEM_PROMPT;
225→  const categoryTree = loadCategoryTree(config);
226→
227→  let totalInputTokens = 0;
228→  let totalOutputTokens = 0;
229→  let totalCost = 0;
230→
231→  for (const candidate of toClassify) {
232→    // Budget check before each call
233→    if (maxBudget !== undefined && totalCost >= maxBudget) {
234→      core.warning(`Budget limit reached ($${totalCost.toFixed(4)} >= $${maxBudget}). Skipping remaining ${toClassify.length - classified.length} candidates.`);
235→      break;
236→    }
237→
238→    try {
239→      const response = await withRetry(() =>
240→        client.chat({
241→          model: config.classification.model,
242→          maxTokens: 512,
243→          system: systemPrompt,
244→          messages: [
245→            {
246→              role: "user",
247→              content: buildUserPrompt(candidate, config, categoryTree),
248→            },
249→          ],
250→        })
251→      );
252→
253→      // Track token usage
254→      const inputTokens = response.usage.inputTokens;
255→      const outputTokens = response.usage.outputTokens;
256→      const cost = estimateCost(inputTokens, outputTokens, config.classification.model);
257→
258→      totalInputTokens += inputTokens;
259→      totalOutputTokens += outputTokens;
260→      totalCost += cost;
261→
262→      core.info(`Classification "${candidate.title}": ${inputTokens} in / ${outputTokens} out tokens ($${cost.toFixed(4)})`);
263→
264→
265→      const text = response.text;
266→      const result = parseClassifyResponse(text);
267→
268→      if (result.relevanceScore >= config.classification.threshold) {
269→        classified.push({ ...candidate, ...result });
270→      } else {
271→        core.info(
272→          `Skipping "${candidate.title}" (score ${result.relevanceScore} < threshold ${config.classification.threshold})`
273→        );
274→      }
275→    } catch (error) {
276→      core.warning(
277→        `Classification failed for "${candidate.title}": ${error instanceof Error ? error.message : String(error)}`
278→      );
279→    }
280→  }
281→
282→  // Log summary
283→  core.info(`Classification summary: ${totalInputTokens} input tokens, ${totalOutputTokens} output tokens, estimated cost: $${totalCost.toFixed(4)}`);
284→
285→  return classified;
286→}
