 47→async function run(): Promise<void> {
 48→  try {
 49→    const configPath = core.getInput("config_path");
 50→    const dryRun = core.getInput("dry_run") === "true";
 51→
 52→    core.info(`Loading config from ${configPath}`);
 53→    const config = loadConfig(configPath);
 54→
 55→    // Create LLM provider
 56→    const apiKey = core.getInput("llm_api_key") || core.getInput("anthropic_api_key");
 57→    if (!apiKey) {
 58→      throw new Error("Either llm_api_key or anthropic_api_key must be provided");
 59→    }
 60→    const llmClient = createProvider(config.classification.provider, apiKey);
 61→
 62→    // Load state
 63→    const state = loadState(config.state_file);
 64→
 65→    let result;
 66→    try {
 67→      result = await runPipeline(
 68→        config,
 69→        {
 70→          collect: async (cfg) => collect(cfg, llmClient),
 71→          filter: async (candidates, cfg) => {
 72→            // First filter out already-seen candidates
 73→            const unseen = filterSeenCandidates(candidates, state);
 74→            // Then apply keyword filtering, metadata filtering, and dedup
 75→            const keywordFiltered = filterCandidates(unseen, cfg);
 76→            const metadataFiltered = filterByMetadata(keywordFiltered, cfg);
 77→            const metadataResult = dedup(metadataFiltered, cfg);
 78→
 79→            // Record candidates that were filtered out
 80→            const filteredOut = unseen.filter(
 81→              (c) => !metadataResult.includes(c)
 82→            );
 83→            recordCandidates(state, filteredOut, "filtered");
 84→
 85→            return metadataResult;
 86→          },
 87→          classify: async (candidates, cfg) => {
 88→            const classified = await classifyCandidates(candidates, cfg, llmClient);
 89→
 90→            // Record accepted (classified) and rejected (below threshold) candidates
 91→            const classifiedUrls = new Set(classified.map((c) => c.url));
 92→            const rejected = candidates.filter(
 93→              (c) => !classifiedUrls.has(c.url)
 94→            );
 95→            recordCandidates(state, classified, "accepted");
 96→            recordCandidates(state, rejected, "rejected");
 97→
 98→            return classified;
