 11→const SYSTEM_PROMPT = `You are an article link extractor. Given the cleaned text of a web page, extract all article or blog post links you can find.
 12→
 13→Respond with ONLY a valid JSON array of objects, each with "title" and "url" fields:
 14→[{"title": "Article Title", "url": "https://example.com/article"}]
 15→
 16→If no article links are found, respond with an empty array: []`;
 17→
 18→export function cleanHtml(html: string): string {
 19→  let text = html;
 20→
 21→  // Remove script, style, nav, footer, header tags and their content
 22→  text = text.replace(/<script[\s\S]*?<\/script>/gi, "");
 23→  text = text.replace(/<style[\s\S]*?<\/style>/gi, "");
 24→  text = text.replace(/<nav[\s\S]*?<\/nav>/gi, "");
 25→  text = text.replace(/<footer[\s\S]*?<\/footer>/gi, "");
 26→  text = text.replace(/<header[\s\S]*?<\/header>/gi, "");
 27→
 28→  // Convert <a href="url">text</a> to [text](url)
 29→  text = text.replace(
 30→    /<a\s+[^>]*href=["']([^"']*)["'][^>]*>([\s\S]*?)<\/a>/gi,
 31→    (_, url, linkText) => {
 32→      const clean = linkText.replace(/<[^>]+>/g, "").trim();
 33→      return clean ? `[${clean}](${url})` : "";
 34→    }
 35→  );
 36→
 37→  // Strip remaining HTML tags
 38→  text = text.replace(/<[^>]+>/g, " ");
 39→
 40→  // Normalize whitespace
 41→  text = text.replace(/\s+/g, " ").trim();
 42→
 43→  return text.slice(0, MAX_HTML_LENGTH);
 44→}
 45→
 46→export function extractFirstJsonArray(text: string): Array<{ title: string; url: string }> {
 47→  const start = text.indexOf("[");
 48→  if (start === -1) return [];
 49→  let depth = 0;
 50→  for (let i = start; i < text.length; i++) {
 51→    if (text[i] === "[") depth++;
 52→    if (text[i] === "]") depth--;
 53→    if (depth === 0) {
 54→      const parsed = JSON.parse(text.slice(start, i + 1));
 55→      if (!Array.isArray(parsed)) return [];
 56→      return parsed.filter(
 57→        (item: unknown) =>
 58→          typeof item === "object" &&
 59→          item !== null &&
 60→          "title" in item &&
 61→          "url" in item &&
 62→          typeof (item as { title: unknown }).title === "string" &&
 63→          typeof (item as { url: unknown }).url === "string"
 64→      );
 65→    }
 66→  }
 67→  return [];
 68→}
 69→
 70→export function resolveUrl(base: string, href: string): string {
 71→  try {
 72→    return new URL(href, base).href;
 73→  } catch {
 74→    return href;
 75→  }
 76→}
 77→
 78→export async function collectWebPages(
 79→  config: RadarConfig,
 80→  fetchFn?: typeof fetch,
 81→  client?: LLMProvider
 82→): Promise<Candidate[]> {
 83→  if (!config.sources.web_pages) return [];
 84→
 85→  if (!client) throw new Error("LLM client is required for web page extraction");
 86→
 87→  const webPages = config.sources.web_pages;
 88→  const fetcher = fetchFn ?? fetch;
 89→  const timeout = webPages.request_timeout;
 90→  const userAgent = webPages.user_agent;
 91→
 92→  const results = await Promise.allSettled(
 93→    webPages.urls.map(async (pageUrl) => {
 94→      core.info(`Fetching web page: ${pageUrl}`);
 95→
 96→      const fetchOptions: RequestInit = {
 97→        signal: AbortSignal.timeout(timeout),
 98→      };
 99→      if (userAgent) {
100→        fetchOptions.headers = { "User-Agent": userAgent };
101→      }
102→      const response = await withRetry(async () => {
103→        const res = await fetcher(pageUrl, fetchOptions);
104→        if (!res.ok) {
105→          throw Object.assign(new Error(`HTTP ${res.status} for ${pageUrl}`), {
106→            status: res.status,
107→          });
108→        }
109→        return res;
110→      });
111→      const html = await response.text();
112→      const cleaned = cleanHtml(html);
113→
114→      core.info(`Extracting links from ${pageUrl} (${cleaned.length} chars)`);
115→
116→      const llmResponse = await withRetry(() =>
117→        client!.chat({
118→          model: webPages.model ?? config.classification.model,
119→          maxTokens: 4096,
120→          system: webPages.extraction_prompt || SYSTEM_PROMPT,
121→          messages: [
122→            {
123→              role: "user",
124→              content: `Extract all article/blog post links from this web page content:\n\n${cleaned}`,
125→            },
126→          ],
127→        })
128→      );
129→
130→      const text = llmResponse.text || "[]";
131→      const links = extractFirstJsonArray(text);
132→
133→      // Resolve relative URLs
134→      const resolved = links.map((link) => ({
135→        ...link,
136→        url: resolveUrl(pageUrl, link.url),
137→      }));
138→
139→      return { pageUrl, links: resolved };
140→    })
141→  );
142→
143→  const candidates: Candidate[] = [];
144→
145→  for (const result of results) {
146→    if (result.status === "rejected") {
147→      core.warning(`Failed to process web page: ${result.reason}`);
148→      continue;
149→    }
150→
151→    const { pageUrl, links } = result.value;
152→
153→    for (const link of links) {
154→      if (!link.url || !link.title) continue;
155→
156→      const text = `${link.title} ${link.url}`;
157→
158→      // Optional keyword filtering
159→      if (webPages.keywords && webPages.keywords.length > 0) {
160→        if (!matchesKeywords(text, webPages.keywords)) continue;
161→      }
162→
163→      candidates.push({
164→        url: link.url,
165→        title: link.title,
166→        description: link.title.slice(0, MAX_DESCRIPTION_LENGTH),
167→        source: "web_page",
168→        metadata: {
169→          pageName: new URL(pageUrl).hostname,
170→        },
171→      });
172→    }
173→  }
174→
175→  return candidates;
176→}
