 1→export type { LLMProvider, LLMRequest, LLMResponse } from "./types";
 2→import type { LLMProvider } from "./types";
 3→
 4→export function createProvider(provider: string, apiKey: string): LLMProvider {
 5→  switch (provider) {
 6→    case "anthropic": {
 7→      const { AnthropicProvider } = require("./providers/anthropic");
 8→      return new AnthropicProvider(apiKey);
 9→    }
10→    case "openai": {
11→      const { OpenAIProvider } = require("./providers/openai");
12→      return new OpenAIProvider(apiKey);
13→    }
14→    case "google": {
15→      const { GoogleProvider } = require("./providers/google");
16→      return new GoogleProvider(apiKey);
17→    }
18→    default:
19→      throw new Error(
20→        `Unknown LLM provider: "${provider}". Supported providers: anthropic, openai, google`
21→      );
22→  }
23→}
