 1→export interface LLMRequest {
 2→  model: string;
 3→  maxTokens: number;
 4→  system: string;
 5→  messages: { role: "user" | "assistant"; content: string }[];
 6→}
 7→
 8→export interface LLMResponse {
 9→  text: string;
10→  usage: { inputTokens: number; outputTokens: number };
11→}
12→
13→export interface LLMProvider {
14→  chat(request: LLMRequest): Promise<LLMResponse>;
15→}
16→

 1→import Anthropic from "@anthropic-ai/sdk";
 2→import type { LLMProvider, LLMRequest, LLMResponse } from "../types";
 3→
 4→export class AnthropicProvider implements LLMProvider {
 5→  private client: Anthropic;
 6→
 7→  constructor(apiKey: string) {
 8→    this.client = new Anthropic({ apiKey });
 9→  }
10→
11→  async chat(request: LLMRequest): Promise<LLMResponse> {
12→    const message = await this.client.messages.create({
13→      model: request.model,
14→      max_tokens: request.maxTokens,
15→      system: request.system,
16→      messages: request.messages,
17→    });
18→
19→    return {
20→      text:
21→        message.content[0].type === "text" ? message.content[0].text : "",
22→      usage: {
23→        inputTokens: message.usage.input_tokens,
24→        outputTokens: message.usage.output_tokens,
25→      },
26→    };
27→  }
28→}
29→

 1→import OpenAI from "openai";
 2→import type { LLMProvider, LLMRequest, LLMResponse } from "../types";
 3→
 4→export class OpenAIProvider implements LLMProvider {
 5→  private client: OpenAI;
 6→
 7→  constructor(apiKey: string) {
 8→    this.client = new OpenAI({ apiKey });
 9→  }
10→
11→  async chat(request: LLMRequest): Promise<LLMResponse> {
12→    const response = await this.client.chat.completions.create({
13→      model: request.model,
14→      max_tokens: request.maxTokens,
15→      messages: [
16→        { role: "system", content: request.system },
17→        ...request.messages,
18→      ],
19→    });
20→
21→    return {
22→      text: response.choices[0]?.message?.content ?? "",
23→      usage: {
24→        inputTokens: response.usage?.prompt_tokens ?? 0,
25→        outputTokens: response.usage?.completion_tokens ?? 0,
26→      },
27→    };
28→  }
29→}
30→

 1→import { GoogleGenerativeAI } from "@google/generative-ai";
 2→import type { LLMProvider, LLMRequest, LLMResponse } from "../types";
 3→
 4→export class GoogleProvider implements LLMProvider {
 5→  private client: GoogleGenerativeAI;
 6→
 7→  constructor(apiKey: string) {
 8→    this.client = new GoogleGenerativeAI(apiKey);
 9→  }
10→
11→  async chat(request: LLMRequest): Promise<LLMResponse> {
12→    const model = this.client.getGenerativeModel({
13→      model: request.model,
14→      systemInstruction: request.system,
15→    });
16→
17→    const contents = request.messages.map((msg) => ({
18→      role: msg.role === "assistant" ? "model" : "user",
19→      parts: [{ text: msg.content }],
20→    }));
21→
22→    const result = await model.generateContent({
23→      contents,
24→      generationConfig: { maxOutputTokens: request.maxTokens },
25→    });
26→
27→    return {
28→      text: result.response.text(),
29→      usage: {
30→        inputTokens: result.response.usageMetadata?.promptTokenCount ?? 0,
31→        outputTokens:
32→          result.response.usageMetadata?.candidatesTokenCount ?? 0,
33→      },
34→    };
35→  }
36→}
